#!/usr/bin/env python3
"""Acme PreToolUse(Bash) hook: keep container pushes on the internal registry.

Registry hooks are plain files with no farrier-specific runtime. This one
follows the same stdin-JSON / stdout-JSON protocol Claude Code uses for
PreToolUse hooks -- the same protocol farrier's own built-in hook templates
use (see src/templates/hooks/secret-shield.py in the farrier repo).
"""

import json
import re
import sys

DENY_PATTERN = re.compile(r"(^|[;&|()\s])docker\s+push\b")
ALLOWED_REGISTRY = "registry.acme.internal"


def emit_deny(reason: str) -> None:
    print(
        json.dumps(
            {
                "hookSpecificOutput": {
                    "hookEventName": "PreToolUse",
                    "permissionDecision": "deny",
                    "permissionDecisionReason": reason,
                }
            }
        )
    )


def command_from_stdin() -> str:
    raw = sys.stdin.read()
    if not raw.strip():
        return ""

    try:
        payload = json.loads(raw)
    except json.JSONDecodeError:
        return ""

    tool_input = payload.get("tool_input") if isinstance(payload, dict) else None
    if isinstance(tool_input, dict):
        return str(tool_input.get("command", ""))
    return ""


def main() -> None:
    command = command_from_stdin()

    if DENY_PATTERN.search(command) and ALLOWED_REGISTRY not in command:
        emit_deny(
            f"Blocked `docker push` to a non-Acme registry. "
            f"Redirect: push to {ALLOWED_REGISTRY}/<image> instead."
        )

    sys.exit(0)


if __name__ == "__main__":
    main()
